     2→
     3→#include "envoy/extensions/filters/http/custom_header_injection/v3/custom_header_injection.pb.h"
     4→
     5→#include "source/common/http/header_utility.h"
     6→#include "source/common/http/utility.h"
     7→
     8→namespace Envoy {
     9→namespace Extensions {
    10→namespace HttpFilters {
    11→namespace CustomHeaderInjection {
    12→
    13→Config::Config(
    14→    const envoy::extensions::filters::http::custom_header_injection::v3::CustomHeaderInjection
    15→        proto_config,
    16→    const bool per_route) {
    17→  // Parse request headers from configuration
    18→  for (const auto& header : proto_config.request_headers()) {
    19→    request_headers_.emplace_back(header.key(), header.value());
    20→  }
    21→
    22→  // Parse response headers from configuration
    23→  for (const auto& header : proto_config.response_headers()) {
    24→    response_headers_.emplace_back(header.key(), header.value());
    25→  }
    26→
    27→  // Per-route configs must have at least one header rule
    28→  if (per_route && request_headers_.empty() && response_headers_.empty()) {
    29→    throw EnvoyException("custom_header_injection filter: Per filter configs must at least "
    30→                         "specify either request or response headers");
    31→  }
    32→}
    33→
    34→CustomHeaderInjectionFilter::CustomHeaderInjectionFilter(const ConfigSharedPtr config)
    35→    : config_(config) {}
    36→
    37→CustomHeaderInjectionFilter::~CustomHeaderInjectionFilter() = default;
    38→
    39→Http::FilterHeadersStatus CustomHeaderInjectionFilter::decodeHeaders(Http::RequestHeaderMap& headers,
    40→                                                                    bool) {
    41→  const auto* config = getConfig();
    42→  if (config->doRequest()) {
    43→    // Inject request headers from configuration
    44→    for (const auto& header : config->requestHeaders()) {
    45→      headers.setCopy(Http::LowerCaseString(header.first), header.second);
    46→    }
    47→  }
    48→
    49→  return Http::FilterHeadersStatus::Continue;
    50→}
    51→
    52→void CustomHeaderInjectionFilter::setDecoderFilterCallbacks(
    53→    Http::StreamDecoderFilterCallbacks& callbacks) {
    54→  decoder_callbacks_ = &callbacks;
    55→}
    56→
    57→Http::FilterHeadersStatus CustomHeaderInjectionFilter::encodeHeaders(Http::ResponseHeaderMap& headers,
    58→                                                                    bool) {
    59→  const auto* config = getConfig();
    60→  if (config->doResponse()) {
    61→    // Inject response headers from configuration
    62→    for (const auto& header : config->responseHeaders()) {
    63→      headers.setCopy(Http::LowerCaseString(header.first), header.second);
    64→    }
    65→  }
    66→
    67→  return Http::FilterHeadersStatus::Continue;
    68→}
    69→
    70→void CustomHeaderInjectionFilter::setEncoderFilterCallbacks(
    71→    Http::StreamEncoderFilterCallbacks& callbacks) {
    72→  encoder_callbacks_ = &callbacks;
    73→}
    74→
    75→const Config* CustomHeaderInjectionFilter::getConfig() const {
    76→  // Cached config pointer
    77→  if (effective_config_) {
    78→    return effective_config_;
    79→  }
    80→
    81→  effective_config_ = Http::Utility::resolveMostSpecificPerFilterConfig<Config>(decoder_callbacks_);
